import React, { useState, useEffect } from 'react';
import axios from 'axios';

const API_URL = 'http://localhost:5000/api';
const api = axios.create({ baseURL: API_URL });
api.interceptors.request.use(config => {
    const token = localStorage.getItem('token');
    if (token) config.headers.Authorization = `Bearer ${token}`;
    return config;
});

const DoctorPortal = () => {
    const [activeTab, setActiveTab] = useState('cohort');
    const [cohortData, setCohortData] = useState({ totalPatients: 12543, atRiskPercentage: 14, avgRecoveryRate: 89 });
    const [generatingReport, setGeneratingReport] = useState(false);
    const [reportResult, setReportResult] = useState('');

    useEffect(() => {
        if (activeTab === 'cohort') {
            api.get('/doctor/cohort').then(res => {
                if (res.data.success) {
                    setCohortData({
                        totalPatients: res.data.totalPatients,
                        atRiskPercentage: res.data.atRiskPercentage,
                        avgRecoveryRate: res.data.avgRecoveryRate
                    });
                }
            }).catch(err => console.error("Cohort data fetch error", err));
        }
    }, [activeTab]);

    const generateAIReport = async () => {
        setGeneratingReport(true);
        setReportResult('');
        try {
            const prompt = `As an expert AI clinician, generate a brief, professional discharge summary report for Patient ID #8921 who presented with severe chest pain but was diagnosed with a Tension Headache by the Random Forest model with 98% confidence. Suggest rest and hydration as next steps. Format nicely but keep it short.`;
            const res = await api.post('/chat', { message: prompt, systemPrompt: 'You are a clinical report generator AI.' });
            setReportResult(res.data.response);
        } catch (error) {
            setReportResult("Failed to generate AI report. Check Gemini API key.");
        } finally {
            setGeneratingReport(false);
        }
    };

    return (
        <div className="portal-container slide-up">
            <div className="portal-sidebar">
                <h3 className="gradient-text" style={{ padding: '0 1rem', marginBottom: '1rem' }}>Clinician Tools</h3>
                <button 
                    className={`portal-sidebar-btn ${activeTab === 'cohort' ? 'active' : ''}`}
                    onClick={() => setActiveTab('cohort')}
                >
                    👥 Cohort Analyzer
                </button>
                <button 
                    className={`portal-sidebar-btn ${activeTab === 'interpretability' ? 'active' : ''}`}
                    onClick={() => setActiveTab('interpretability')}
                >
                    🧠 Model Overview
                </button>
                <button 
                    className={`portal-sidebar-btn ${activeTab === 'reporting' ? 'active' : ''}`}
                    onClick={() => setActiveTab('reporting')}
                >
                    📄 Auto Reporting
                </button>
                <button 
                    className={`portal-sidebar-btn ${activeTab === 'pathways' ? 'active' : ''}`}
                    onClick={() => setActiveTab('pathways')}
                >
                    🛤️ Diagnostic Pathways
                </button>
                <button 
                    className={`portal-sidebar-btn ${activeTab === 'alerts' ? 'active' : ''}`}
                    onClick={() => setActiveTab('alerts')}
                >
                    🚨 Predictive Alerts
                </button>
            </div>

            <div className="portal-content">
                {activeTab === 'cohort' && (
                    <div className="portal-panel">
                        <h2>Patient Cohort Analyzer</h2>
                        <p className="subtitle">Compare sub-populations and analyze trends.</p>
                        <div className="data-grid">
                            <div className="data-card">
                                <span className="data-label">Total Patients analyzed</span>
                                <span className="data-value">{cohortData.totalPatients}</span>
                            </div>
                            <div className="data-card">
                                <span className="data-label">At-Risk Group (High)</span>
                                <span className="data-value" style={{color: '#ef4444'}}>{cohortData.atRiskPercentage}%</span>
                            </div>
                            <div className="data-card">
                                <span className="data-label">Avg. Recovery Rate</span>
                                <span className="data-value" style={{color: '#10b981'}}>{cohortData.avgRecoveryRate}%</span>
                            </div>
                        </div>
                        <div className="chart-placeholder">
                            [Interactive Cohort Graph Visualization]
                        </div>
                    </div>
                )}

                {activeTab === 'interpretability' && (
                    <div className="portal-panel">
                        <h2>Model Interpretability</h2>
                        <p className="subtitle">Understand which features influenced the AI's diagnosis the most.</p>
                        <div className="chart-placeholder" style={{height: '400px'}}>
                            [SHAP / LIME Feature Importance Visualization]
                        </div>
                        <div className="data-grid">
                            <div className="data-card">
                                <span className="data-label">Top Feature</span>
                                <span className="data-value" style={{fontSize: '1.5rem'}}>Blood Pressure (Systolic)</span>
                            </div>
                            <div className="data-card">
                                <span className="data-label">Model Confidence Bias</span>
                                <span className="data-value" style={{fontSize: '1.5rem'}}>Minimal (&lt; 2%)</span>
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'reporting' && (
                    <div className="portal-panel">
                        <h2>Automated Reporting and Referral</h2>
                        <p className="subtitle">Generate standard formatted reports for cross-department referrals.</p>
                        <div className="action-card">
                            <div>
                                <h3>Generate Patient Summary</h3>
                                <p>Includes AI hypothesis, patient history, and suggested next steps.</p>
                            </div>
                            <button className="btn-secondary" style={{background: 'white', color: '#667eea', border: 'none'}} onClick={generateAIReport} disabled={generatingReport}>
                                {generatingReport ? '⏳ Analyzing...' : '✨ Generate AI Summary'}
                            </button>
                        </div>
                        {reportResult && (
                            <div className="timeline-event" style={{marginTop: '2rem', borderLeftColor: '#667eea', background: 'white', padding: '1rem', borderRadius: '8px'}}>
                                <div className="timeline-time">AI Generated Summary for ID #8921</div>
                                <div className="timeline-desc" style={{whiteSpace: 'pre-wrap', marginTop: '1rem', color: '#4a5568'}}>
                                    {reportResult}
                                </div>
                            </div>
                        )}
                        <div className="timeline-event" style={{marginTop: '2rem'}}>
                            <div className="timeline-time">Today, 09:41 AM</div>
                            <div className="timeline-desc">
                                <strong>Report Sent:</strong> Referral to Cardiology (Dr. Smith) for Patient ID #8921. Status: <em>Delivered</em>
                            </div>
                        </div>
                        <div className="timeline-event">
                            <div className="timeline-time">Yesterday, 14:20 PM</div>
                            <div className="timeline-desc">
                                <strong>Report Generated:</strong> Routine discharge summary for Patient ID #8843. Status: <em>Saved to EHR</em>
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'pathways' && (
                    <div className="portal-panel">
                        <h2>Diagnostic Pathways & Treatment Suggestions</h2>
                        <p className="subtitle">AI-assisted guided pathways for complex cases.</p>
                        <div className="feature-grid">
                            <div className="data-card">
                                <h3>Pathway Start</h3>
                                <p>Symptom: Severe Chest Pain</p>
                                <button className="btn-primary" style={{marginTop: '1rem'}}>Initiate Protocol</button>
                            </div>
                            <div className="data-card">
                                <h3>Active: Patient #6621</h3>
                                <p>Current Stage: Awaiting Troponin levels.</p>
                                <div style={{width: '100%', background: '#e2e8f0', height: '10px', borderRadius: '5px', marginTop: '1rem'}}>
                                    <div style={{width: '40%', background: '#10b981', height: '10px', borderRadius: '5px'}}></div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'alerts' && (
                    <div className="portal-panel">
                        <h2>Predictive Alerts & Notifications</h2>
                        <p className="subtitle">Real-time ward monitoring and early warning system.</p>
                        <div style={{display: 'flex', flexDirection: 'column', gap: '1rem'}}>
                            <div className="data-card" style={{borderLeft: '5px solid #ef4444'}}>
                                <strong>URGENT: Patient #1102 (Bed 4)</strong>
                                <p>AI detects 85% probability of imminent sepsis onset based on vitals trend.</p>
                            </div>
                            <div className="data-card" style={{borderLeft: '5px solid #f59e0b'}}>
                                <strong>WARNING: Patient #0994 (Bed 12)</strong>
                                <p>Blood pressure dropping over past 2 hours. Review advised.</p>
                            </div>
                            <div className="data-card" style={{borderLeft: '5px solid #10b981'}}>
                                <strong>UPDATE: Ward 3 Capacity</strong>
                                <p>Normal. 4 beds available. Discharge predicting 2 more beds by 5 PM.</p>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default DoctorPortal;
